import { useState, useEffect, useCallback, useRef } from 'react';
import { getApiBase } from '../utils/platform';

/**
 * usePortfolioContext — fetches telemetry + positions and builds a context string
 * for injection into AI chat messages.
 *
 * Returns:
 *   contextEnabled  — boolean toggle state
 *   setContextEnabled — setter
 *   contextString   — formatted portfolio summary string (or null if disabled/loading)
 *   contextLoading  — true while fetching
 *   refreshContext   — manually trigger a refresh
 */
export default function usePortfolioContext() {
  const [contextEnabled, setContextEnabled] = useState(true);
  const [contextString, setContextString] = useState(null);
  const [contextLoading, setContextLoading] = useState(false);
  const lastFetchRef = useRef(0);

  const API = getApiBase();

  const buildContext = useCallback(async () => {
    if (!contextEnabled) {
      setContextString(null);
      return null;
    }

    // Throttle: don't refetch within 15 seconds
    const now = Date.now();
    if (now - lastFetchRef.current < 15000 && contextString) {
      return contextString;
    }

    setContextLoading(true);
    try {
      const [telRes, posRes] = await Promise.allSettled([
        fetch(`${API}/telemetry/latest`).then(r => r.ok ? r.json() : null),
        fetch(`${API}/positions`).then(r => r.ok ? r.json() : null),
      ]);

      const telemetry = telRes.status === 'fulfilled' ? telRes.value : null;
      const positions = posRes.status === 'fulfilled' ? posRes.value : null;

      const lines = ['[PORTFOLIO CONTEXT]'];

      // Telemetry / bot status — exclude paper/marketing bots
      const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
      if (telemetry) {
        const rawBots = Array.isArray(telemetry) ? telemetry : (telemetry.bots || [telemetry]);
        // When bots is an object (keyed by name), convert to array and filter
        let bots;
        if (Array.isArray(rawBots)) {
          bots = rawBots.filter(b => !PAPER_BOTS.has((b.bot_name || b.name || '').toLowerCase()));
        } else if (typeof rawBots === 'object') {
          bots = Object.entries(rawBots)
            .filter(([k]) => !PAPER_BOTS.has(k.toLowerCase()))
            .map(([k, v]) => ({ ...v, bot_name: v.bot_name || k }));
        } else {
          bots = [];
        }
        for (const bot of bots) {
          const name = bot.bot_name || bot.name || 'Unknown';
          const equity = bot.equity ?? bot.net_liquidation ?? bot.nlv;
          const pnl = bot.daily_pnl ?? bot.pnl ?? bot.unrealized_pnl;
          const status = bot.status || (bot.heartbeat_age_s != null && bot.heartbeat_age_s < 120 ? 'ONLINE' : 'OFFLINE');
          lines.push(`Bot ${name}: status=${status}${equity != null ? `, equity=$${Number(equity).toLocaleString()}` : ''}${pnl != null ? `, daily_pnl=$${Number(pnl).toFixed(2)}` : ''}`);
        }
      }

      // Market hours estimate (Safari-safe — avoid new Date(toLocaleString()))
      const now = new Date();
      const etParts = new Intl.DateTimeFormat('en-US', {
        timeZone: 'America/New_York', hour: 'numeric', minute: 'numeric', weekday: 'short', hour12: false,
      }).formatToParts(now);
      const _get = (type) => etParts.find(p => p.type === type)?.value || '';
      const _dayMap = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
      const etHour = parseInt(_get('hour'), 10) || 0;
      const etMin = parseInt(_get('minute'), 10) || 0;
      const etTime = etHour + etMin / 60;
      const dayOfWeek = _dayMap[_get('weekday')] ?? now.getDay();
      const isWeekday = dayOfWeek >= 1 && dayOfWeek <= 5;
      const isMarketHours = isWeekday && etTime >= 9.5 && etTime < 16;
      const isPreMarket = isWeekday && etTime >= 4 && etTime < 9.5;
      const isAfterHours = isWeekday && etTime >= 16 && etTime < 20;
      const marketStatus = isMarketHours ? 'OPEN' : isPreMarket ? 'PRE-MARKET' : isAfterHours ? 'AFTER-HOURS' : 'CLOSED';
      lines.push(`Market: ${marketStatus} (ET ${String(Math.floor(etTime)).padStart(2, '0')}:${String(Math.round((etTime % 1) * 60)).padStart(2, '0')})`);

      // Positions
      if (positions) {
        const posList = Array.isArray(positions) ? positions : (positions.positions || []);
        if (posList.length === 0) {
          lines.push('Positions: none');
        } else {
          lines.push(`Positions (${posList.length}):`);
          for (const pos of posList.slice(0, 20)) {
            const sym = pos.symbol || pos.ticker || '??';
            const qty = pos.quantity ?? pos.qty ?? pos.size ?? 0;
            const upnl = pos.unrealized_pnl ?? pos.pnl ?? pos.unrealizedPnl;
            const avgCost = pos.avg_cost ?? pos.avgCost ?? pos.average_cost;
            const mktVal = pos.market_value ?? pos.marketValue;
            let detail = `  ${sym}: qty=${qty}`;
            if (avgCost != null) detail += `, avg=$${Number(avgCost).toFixed(2)}`;
            if (mktVal != null) detail += `, mktVal=$${Number(mktVal).toFixed(2)}`;
            if (upnl != null) detail += `, unrealizedPnl=$${Number(upnl).toFixed(2)}`;
            lines.push(detail);
          }
          if (posList.length > 20) lines.push(`  ... and ${posList.length - 20} more`);
        }
      }

      lines.push('[END PORTFOLIO CONTEXT]');
      const ctx = lines.join('\n');
      setContextString(ctx);
      lastFetchRef.current = Date.now();
      return ctx;
    } catch (err) {
      console.warn('Portfolio context fetch failed:', err);
      setContextString(null);
      return null;
    } finally {
      setContextLoading(false);
    }
  }, [contextEnabled, API]);

  // Fetch on mount and when toggled on
  useEffect(() => {
    if (contextEnabled) {
      buildContext();
    } else {
      setContextString(null);
    }
  }, [contextEnabled]);

  return {
    contextEnabled,
    setContextEnabled,
    contextString,
    contextLoading,
    refreshContext: buildContext,
  };
}
